	@Test
	public void exactValuesShapesCollapseSafelyAtTheConfiguredCap() throws Exception {
		BindingSetAssignment values = values();
		ScopeAnalysis analysis = ScopeAnalysis.analyze(new QueryRoot(values));

		Object exactOracle = oracle(analysis, 8);
		Object exact = analyze(exactOracle, values);
		assertThat(invoke(exact, "size")).isEqualTo(3);
		assertThat(invoke(exact, "precision").toString()).isEqualTo("EXACT");
		assertThat(everyShapeBinds(exactOracle, exact, Set.of("x"))).isTrue();
		assertThat(everyShapeBinds(exactOracle, exact, Set.of("y"))).isFalse();

		Object cappedOracle = oracle(analysis, 2);
		Object capped = analyze(cappedOracle, values);
		assertThat((int) invoke(capped, "size")).isLessThanOrEqualTo(2);
		assertThat(invoke(capped, "precision").toString()).isEqualTo("OVER_APPROXIMATION");
		assertThat(everyShapeBinds(cappedOracle, capped, Set.of("x"))).isTrue();
		assertThat(everyShapeBinds(cappedOracle, capped, Set.of("y"))).isFalse();
	}

